import{_ as E,C as d,o as e,c,j as r,a as s,b as l,w as n,E as o,a4 as p,a5 as i}from"./chunks/framework.sOZL8giL.js";const C=JSON.parse('{"title":"动态编排与迭代","description":"","frontmatter":{},"headers":[],"relativePath":"04-多Agent架构/04-动态编排与迭代.md","filePath":"04-多Agent架构/04-动态编排与迭代.md","lastUpdated":null}'),u={name:"04-多Agent架构/04-动态编排与迭代.md"};function h(b,a,B,A,m,k){const t=d("Mermaid");return e(),c("div",null,[a[2]||(a[2]=r("h1",{id:"动态编排与迭代",tabindex:"-1"},[s("动态编排与迭代 "),r("a",{class:"header-anchor",href:"#动态编排与迭代","aria-label":'Permalink to "动态编排与迭代"'},"​")],-1)),a[3]||(a[3]=r("blockquote",null,[r("p",null,[s("本章是 "),r("strong",null,"Hermes Engineering 系列"),s("第 4 模块的第 4 章。")])],-1)),a[4]||(a[4]=r("p",null,"从静态 Workflow 到动态编排——Orchestrator-Workers 动态拆分并行，Evaluator-Optimizer 用反馈循环打磨质量。",-1)),a[5]||(a[5]=r("hr",null,null,-1)),a[6]||(a[6]=r("h2",{id:"orchestrator-workers-动态拆分的并行架构",tabindex:"-1"},[s("Orchestrator-Workers：动态拆分的并行架构 "),r("a",{class:"header-anchor",href:"#orchestrator-workers-动态拆分的并行架构","aria-label":'Permalink to "Orchestrator-Workers：动态拆分的并行架构"'},"​")],-1)),(e(),l(p,null,{default:n(()=>[o(t,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%9F%A5%E8%AF%A2%5D%20--%3E%20B%5BOrchestrator%20%E7%BC%96%E6%8E%92%E5%99%A8%3Cbr%2F%3E%E5%88%86%E6%9E%90%E4%BB%BB%E5%8A%A1%20%E5%8A%A8%E6%80%81%E6%8B%86%E5%88%86%5D%0A%20%20%20%20B%20--%3E%20C%5BWorker%201%3A%20%E5%AD%90%E4%BB%BB%E5%8A%A1A%5D%0A%20%20%20%20B%20--%3E%20D%5BWorker%202%3A%20%E5%AD%90%E4%BB%BB%E5%8A%A1B%5D%0A%20%20%20%20B%20--%3E%20E%5BWorker%203%3A%20%E5%AD%90%E4%BB%BB%E5%8A%A1C%5D%0A%20%20%20%20C%20--%3E%7C%E7%BB%93%E6%9E%9C%7C%20F%5BOrchestrator%20%E6%B1%87%E6%80%BB%5D%0A%20%20%20%20D%20--%3E%7C%E7%BB%93%E6%9E%9C%7C%20F%0A%20%20%20%20E%20--%3E%7C%E7%BB%93%E6%9E%9C%7C%20F%0A%20%20%20%20F%20--%3E%20G%7B%E9%9C%80%E8%A6%81%E6%9B%B4%E5%A4%9AWorker%EF%BC%9F%7D%0A%20%20%20%20G%20--%3E%7C%E6%98%AF%7C%20H%5B%E6%B4%BE%E7%94%9F%E6%96%B0%20Worker%5D%0A%20%20%20%20H%20--%3E%20F%0A%20%20%20%20G%20--%3E%7C%E5%90%A6%7C%20I%5B%E8%BE%93%E5%87%BA%E6%9C%80%E7%BB%88%E7%BB%93%E6%9E%9C%5D%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[s(" Loading... ",-1)])]),_:1})),a[7]||(a[7]=i(`<blockquote><p>💡 <strong>图解：</strong> 编排器做元决策——它不做具体工作，只决定谁做什么、拆几份、何时收工。</p></blockquote><p>前面讲的四种模式都是确定性编排——流程在执行前就已确定。Orchestrator-Workers 模式则引入了动态性：编排器根据实时情况动态决定如何拆分任务和分配 Worker。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询 → [Orchestrator: 分析任务，动态拆分子任务]</span></span>
<span class="line"><span>              ├→ [Worker 1: 处理子任务A]</span></span>
<span class="line"><span>              ├→ [Worker 2: 处理子任务B]</span></span>
<span class="line"><span>              └→ [Worker 3: 处理子任务C]</span></span>
<span class="line"><span>         → [Orchestrator: 汇总结果，决定是否需要更多 Worker]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="与-sectioning-的区别" tabindex="-1">与 Sectioning 的区别 <a class="header-anchor" href="#与-sectioning-的区别" aria-label="Permalink to &quot;与 Sectioning 的区别&quot;">​</a></h3><p>Sectioning 的分割是预设的——你事先知道要把文档分成三段。Orchestrator-Workers 的分割是动态的——编排器先审视任务，根据复杂度和依赖关系决定如何拆分、派几个 Worker。</p><p>这意味着编排器本身是一个 LLM 调用，它做的是元决策：不做具体工作，只决定谁做什么。</p><h3 id="优势与代价" tabindex="-1">优势与代价 <a class="header-anchor" href="#优势与代价" aria-label="Permalink to &quot;优势与代价&quot;">​</a></h3><p><strong>优势</strong>：能处理未知结构的任务——你不需要提前知道任务能分成几部分。Worker 数量和分配随任务复杂度自动调整。</p><p><strong>代价</strong>：编排器的决策质量是瓶颈——拆分不当会导致 Worker 做无用功。额外的编排器调用增加延迟和成本。Worker 之间可能存在隐性依赖，动态拆分可能忽略这些依赖。</p><h3 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h3><p>复杂研究任务：用户问&quot;分析 SaaS 行业的 AI 趋势&quot;。Orchestrator 先搜索初步信息，发现需要深入三个方向（基础设施层、应用层、投资趋势），动态派生三个 Worker 各自研究，最后汇总。</p><hr><h2 id="evaluator-optimizer-用反馈循环打磨质量" tabindex="-1">Evaluator-Optimizer：用反馈循环打磨质量 <a class="header-anchor" href="#evaluator-optimizer-用反馈循环打磨质量" aria-label="Permalink to &quot;Evaluator-Optimizer：用反馈循环打磨质量&quot;">​</a></h2>`,13)),(e(),l(p,null,{default:n(()=>[o(t,{id:"mermaid-53",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E6%9F%A5%E8%AF%A2%5D%20--%3E%20B%5BGenerator%3A%20%E7%94%9F%E6%88%90%E5%88%9D%E7%A8%BF%5D%0A%20%20%20%20B%20--%3E%20C%5BEvaluator%3A%20%E8%AF%84%E4%BC%B0%E8%B4%A8%E9%87%8F%5D%0A%20%20%20%20C%20--%3E%20D%7B%E8%BE%BE%E6%A0%87%EF%BC%9F%7D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20E%5B%E8%BE%93%E5%87%BA%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20F%5BEvaluator%20%E7%BB%99%E5%87%BA%3Cbr%2F%3E%E5%85%B7%E4%BD%93%E5%8F%AF%E6%93%8D%E4%BD%9C%E7%9A%84%E5%8F%8D%E9%A6%88%5D%0A%20%20%20%20F%20--%3E%20G%5BGenerator%20%E6%A0%B9%E6%8D%AE%E5%8F%8D%E9%A6%88%E6%94%B9%E8%BF%9B%5D%0A%20%20%20%20G%20--%3E%20C%0A%20%20%20%20D%20--%3E%7C%E8%BE%BE%E5%88%B0%E6%9C%80%E5%A4%A7%E6%AC%A1%E6%95%B0%7C%20H%5B%E6%8D%A2%E6%A8%A1%E5%9E%8B%E6%88%96%E6%94%B9Prompt%5D%0A%20%20%20%20style%20D%20fill%3A%23f96%0A"})]),fallback:n(()=>[...a[1]||(a[1]=[s(" Loading... ",-1)])]),_:1})),a[8]||(a[8]=i(`<blockquote><p>💡 <strong>图解：</strong> 生成器和评估器是独立 Agent——评估不受&quot;自己写的&quot;偏见干扰，标准越客观迭代越有效。</p></blockquote><p>这是 Reflection 模式的系统化实现。生成器产出初稿，评估器打分并给反馈，如果不达标则把反馈喂回生成器重新生成。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询 → [Generator: 生成初稿]</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>         [Evaluator: 评估质量，给出分数和反馈]</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>         [达标？] → 是 → 输出</span></span>
<span class="line"><span>              ↓ 否</span></span>
<span class="line"><span>         [Generator: 根据反馈改进]</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>         [Evaluator: 再次评估]</span></span>
<span class="line"><span>              ↓ (循环直到达标或最大次数)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="关键设计" tabindex="-1">关键设计 <a class="header-anchor" href="#关键设计" aria-label="Permalink to &quot;关键设计&quot;">​</a></h3><p><strong>评估标准必须客观可衡量</strong>：完整性（覆盖所有要求的方面）、准确性（数据逻辑正确）、格式规范。差的标准是&quot;写得更好&quot;&quot;更有说服力&quot;——模型无法可靠地评估主观质量。</p><p><strong>反馈必须具体可操作</strong>：不能说&quot;第三段不好&quot;，要指出具体问题（&quot;第三段缺少数据支持，需要添加 2024 年市场份额数据&quot;）。</p><p><strong>最大迭代次数</strong>：防止无限循环。通常 2-3 次迭代足够——如果 3 次还没达标，换模型或改 Prompt 比继续迭代更有效。</p><h3 id="与-reflection-的区别" tabindex="-1">与 Reflection 的区别 <a class="header-anchor" href="#与-reflection-的区别" aria-label="Permalink to &quot;与 Reflection 的区别&quot;">​</a></h3><p>Reflection 通常在单 Agent 内部实现——同一个 Agent 先生成再检查。Evaluator-Optimizer 是两个独立 Agent——Generator 和 Evaluator 有独立的上下文和角色定义。独立 Agent 的优势是评估不受生成过程的干扰——Generator 不会因为&quot;自己写的&quot;就偏向认可。</p><h3 id="成本考量" tabindex="-1">成本考量 <a class="header-anchor" href="#成本考量" aria-label="Permalink to &quot;成本考量&quot;">​</a></h3><p>每次迭代都是一次完整的生成 + 一次评估。3 次迭代 = 6 欍 LLM 调用。只对高价值输出使用这种模式——技术文档、研究报告、关键决策支持。</p><hr><h2 id="两种模式的组合" tabindex="-1">两种模式的组合 <a class="header-anchor" href="#两种模式的组合" aria-label="Permalink to &quot;两种模式的组合&quot;">​</a></h2><p>在实际系统中，这两种模式经常组合使用：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户查询 → [Orchestrator: 拆分任务]</span></span>
<span class="line"><span>              ├→ [Worker 1 + Evaluator-Optimizer 循环]</span></span>
<span class="line"><span>              ├→ [Worker 2 + Evaluator-Optimizer 循环]</span></span>
<span class="line"><span>              └→ [Worker 3 + Evaluator-Optimizer 循环]</span></span>
<span class="line"><span>         → [Orchestrator: 汇总并做最终检查]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>每个 Worker 内部可以有自己的质量打磨循环，Orchestrator 负责全局协调和最终汇总。</p><p>但要注意：嵌套的动态性和迭代会显著增加系统的复杂度和成本。在生产环境中，需要对这种组合有明确的成本预算和超时控制。</p><hr><h2 id="从静态到动态的演进" tabindex="-1">从静态到动态的演进 <a class="header-anchor" href="#从静态到动态的演进" aria-label="Permalink to &quot;从静态到动态的演进&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>静态 Workflow</th><th>动态编排</th></tr></thead><tbody><tr><td>流程确定时机</td><td>执行前</td><td>执行中</td></tr><tr><td>灵活性</td><td>低</td><td>高</td></tr><tr><td>可预测性</td><td>高</td><td>低</td></tr><tr><td>成本</td><td>可预估</td><td>难预估</td></tr><tr><td>调试难度</td><td>低</td><td>高</td></tr><tr><td>适用场景</td><td>流程已知的标准任务</td><td>结构未知的探索任务</td></tr></tbody></table><p>演进路径：大多数系统从静态 Workflow 开始，当发现预设流程无法覆盖足够场景时，逐步引入动态编排。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Orchestrator-Workers：编排器动态拆分任务派生 Worker，适合未知结构任务</li><li>Evaluator-Optimizer：生成→评估→改进循环，评估标准必须客观可衡量</li><li>两种模式组合使用但注意复杂度和成本控制</li><li>从静态到动态的演进：先用简单 Workflow 覆盖，不够再引入动态</li></ul><hr><p><strong>上一章</strong>: <a href="./03-六种Workflow模式.html">六种Workflow模式</a> | <strong>下一章</strong>: <a href="./05-选型与实践.html">选型与实践</a></p>`,26))])}const f=E(u,[["render",h]]);export{C as __pageData,f as default};
